import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { Save, Calendar, ShoppingBag, Hash, Receipt, CreditCard, User } from 'lucide-react';

const Lancamento = () => {
  const [cartoes, setCartoes] = useState([]); // Estado para a lista de cartões
  const [form, setForm] = useState({
    descricao: '', 
    valor_total: '', 
    loja: '', 
    pedido: '', 
    nota_fiscal: '', 
    responsavel: '',
    parcelado: false, 
    num_parcelas: 1, 
    cartao: '', // Novo campo no estado
    data_compra: new Date().toISOString().split('T')[0]
  });

  // Busca cartões ao carregar a página
  useEffect(() => {
    fetchCartoes();
  }, []);

  async function fetchCartoes() {
    const { data, error } = await supabase
      .from('cartoes')
      .select('id, nome')
      .order('nome', { ascending: true });
    
    if (!error) setCartoes(data || []);
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (parseFloat(form.valor_total) <= 0) {
      alert("O valor deve ser maior que zero!");
      return;
    }

    // Validação extra: se for parcelado, o cartão deve ser selecionado
    if (form.parcelado && !form.cartao) {
      alert("Por favor, selecione o cartão utilizado.");
      return;
    }

    const { error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: form.parcelado ? parseInt(form.num_parcelas) : 1,
        // Se não for parcelado, limpamos o cartão (opcional)
        cartao: form.parcelado ? form.cartao : null
      }]);

    if (error) alert("Erro ao salvar: " + error.message);
    else {
      alert("✅ Gasto registrado com sucesso!");
      window.location.reload();
    }
  };

  const labelStyle = { 
    display: 'flex', 
    alignItems: 'center', 
    gap: '8px', 
    fontSize: '0.75rem', 
    fontWeight: '700', 
    color: 'var(--text-muted)', 
    marginBottom: '8px',
    textTransform: 'uppercase'
  };

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '20px' }}>Novo Lançamento</h2>
      
      <div className="card">
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
            <div className="input-group">
              <label style={labelStyle}><Calendar size={14} /> Data</label>
              <input type="date" className="form-control" value={form.data_compra} required onChange={e => setForm({...form, data_compra: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><ShoppingBag size={14} /> Loja</label>
              <input placeholder="Ex: Amazon" className="form-control" onChange={e => setForm({...form, loja: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><User size={14} /> Responsável</label>
              <input placeholder="Quem comprou?" className="form-control" onChange={e => setForm({...form, responsavel: e.target.value})} />
            </div>
          </div>

          <div className="input-group">
            <label style={labelStyle}>Descrição</label>
            <input placeholder="O que você comprou?" className="form-control" required onChange={e => setForm({...form, descricao: e.target.value})} />
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'}}>
            <div className="input-group">
              <label style={labelStyle}><Hash size={14} /> Pedido</label>
              <input placeholder="Opcional" className="form-control" onChange={e => setForm({...form, pedido: e.target.value})} />
            </div>
            <div className="input-group">
              <label style={labelStyle}><Receipt size={14} /> Nota Fiscal</label>
              <input placeholder="Opcional" className="form-control" onChange={e => setForm({...form, nota_fiscal: e.target.value})} />
            </div>
          </div>

          {/* Seção Dinâmica de Pagamento */}
          <div 
            className={form.parcelado ? "row-mobile" : ""} 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: form.parcelado ? '1.2fr 0.8fr 0.8fr 1.2fr' : '1fr 1fr', 
              gap: '15px', 
              alignItems: 'end' 
            }}
          >
            <div className="input-group">
              <label style={labelStyle}>Valor Total</label>
              <input type="number" step="0.01" placeholder="0,00" className="form-control" required onChange={e => setForm({...form, valor_total: e.target.value})} />
            </div>

            <div style={{ paddingBottom: '12px' }}>
              <label className="checkbox-container" style={{ 
                background: form.parcelado ? 'var(--primary-light)' : '#f8fafc', 
                padding: '12px 8px', 
                borderRadius: '10px',
                border: form.parcelado ? '1px solid var(--primary)' : '1px solid var(--border)',
                display: 'flex',
                justifyContent: 'center',
                cursor: 'pointer'
              }}>
                <input type="checkbox" checked={form.parcelado} onChange={e => setForm({...form, parcelado: e.target.checked})} />
                <span style={{ fontWeight: '700', fontSize: '0.7rem', color: form.parcelado ? 'var(--primary)' : 'inherit' }}>
                   {form.parcelado ? 'PARCELADO' : 'PARCELAR?'}
                </span>
              </label>
            </div>

            {form.parcelado && (
              <>
                <div className="input-group fade-in">
                  <label style={labelStyle}>Parcelas</label>
                  <input 
                    type="number" 
                    min="2" 
                    placeholder="2x"
                    className="form-control" 
                    required 
                    value={form.num_parcelas}
                    onChange={e => setForm({...form, num_parcelas: e.target.value})} 
                    style={{ borderColor: 'var(--primary)', fontWeight: '700' }}
                  />
                </div>

                <div className="input-group fade-in">
                  <label style={labelStyle}><CreditCard size={14} /> Cartão</label>
                  <select 
                    className="form-control" 
                    required 
                    value={form.cartao}
                    onChange={e => setForm({...form, cartao: e.target.value})}
                    style={{ borderColor: 'var(--primary)', cursor: 'pointer' }}
                  >
                    <option value="">Selecione...</option>
                    {cartoes.map(c => (
                      <option key={c.id} value={c.nome}>{c.nome}</option>
                    ))}
                  </select>
                </div>
              </>
            )}
          </div>

          <button type="submit" className="btn-primary" style={{ height: '55px', marginTop: '10px' }}>
            <Save size={20} style={{ marginRight: '10px' }} /> Salvar Lançamento
          </button>
        </form>
      </div>
    </div>
  );
};

export default Lancamento;
